#include <iostream>
#include <fstream>
using namespace std;

int main() {
    ifstream inFile("test.txt");
    string line;
    if (inFile.is_open()) {
        while (getline(inFile, line)) {
            cout << line << endl;
        }
        inFile.close();
    }
    return 0;
}

