    Person p = {"Alice", 30};
    ofstream outFile("person.dat", ios::binary);
    outFile.write((char*)&p, sizeof(p));
    outFile.close();
    return 0;
}

#include <iostream>
#include <fstream>
using namespace std;

class Person {
public:
    char name[50];
    int age;
};

int main() {
    Person p;
    ifstream inFile("person.dat", ios::binary);
    inFile.read((char*)&p, sizeof(p));
    cout << "Age: " << p.age << endl;
    inFile.close();
    return 0;
}

